var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"환영합니다, 손님.","JPN":"いらっしゃいませ、お客様。","ENG":"Welcome, madam.","TWN":"歡迎光臨。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"GUARD_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"신분증을 제시해 주시겠습니까. 이 앞은 입주자 분들만 출입 가능합니다.","JPN":"身分証を拝見します。この先は入居者のみが出入りできますので。","ENG":"May I check your ID, please? This area is limited to residents only.","TWN":"請出示您的身份證，這裡面只允許住戶出入。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"GUARD_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"아, 아뇨. 저는 <color=#ffd34c>그릴 파티</color>에서 왔어요.","JPN":"あ、いいえ。私は<color=#ffd34c>グリルパーティー</color>から来ました。","ENG":"Oh, no. I'm here on behalf of <color=#ffd34c>Grill Party</color>.","TWN":"不是的，我是代表<color=#ffd34c>格里爾派提</color>來的。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUARD_NPC_NANAHARA2_NULL","text":{"KOREA":"아. 연락은 받았습니다. 이쪽으로 오시죠.","JPN":"あ。連絡は受けています。こちらへどうぞ。","ENG":"Ah, I see. We got the message. Please, right this way.","TWN":"是的，我有收到通知，這邊請。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"GUARD_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그릴 파티에 전합니다. 전력을 다하세요.","JPN":"グリルパーティーに伝えます。全力を尽くしてください。","ENG":"I send this message to Grill Party. Try your best.","TWN":"請轉告格里爾派提，叫他們全力以赴。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"안 그러면 회사 문 닫아야 할 걸요.","JPN":"じゃないと、会社潰される羽目になりますよ。","ENG":"If you don't, your company might have to close down.","TWN":"否則公司會關門大吉的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"겁나면 지금 문 닫고 내빼시든지. 메롱.","JPN":"怖かったら今からでも廃業して逃げたら？　べーっ。","ENG":"Scared? Then close now and run away. Bleh!","TWN":"害怕的話現在就關門溜走吧，ㄌㄩㄝ～"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"믿고 맡겼더니 일처리를 어떻게 한 건가?","JPN":"信頼して任せておいたが、いったい何をやっているんだ？","ENG":"We trusted you to do your job. Look what you've done!","TWN":"我是出於信任才把事情交給你的，你是怎麼辦事的？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"거친 애들이면 잘 타일러서 보냈어야지.","JPN":"乱暴なやつらなら、ちゃんと言い聞かせて追い出すべきだろう。","ENG":"You should've let them down easy if you knew they were so boorish!","TWN":"知道對方脾氣不好，就該好好哄哄再送走。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"죄, 죄송합니다.","JPN":"も、申し訳ありません。","ENG":"M-my apologies.","TWN":"對，對不起。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"업무를 처리하는 과정에서 놓친 부분이 있었습니다. 주의하겠습니다.","JPN":"仕事を処理する途中で見逃したところがありました。気をつけます。","ENG":"I made some mistakes while taking care of things. I promise to be more careful from now on.","TWN":"處理過程中我確實有疏忽的地方，我會注意的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"주의? 저건 선전 포고야!","JPN":"気をつける？　あれは宣戦布告だ！","ENG":"Careful? They literally declared war!","TWN":"注意？那是宣戰！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"저대로 설치게 놔두면 우리 회사 이미지는 박살이라고!","JPN":"あのまま暴れさせておけば、会社のイメージが悪くなる！","ENG":"Let the kid roam free, and this company's done for!","TWN":"如果就那樣放任不管，我們公司的形象會毀掉的！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"이번 경기에서 확실하게 끝장을 내야 돼. 두 번 다시 덤빌 일 없게.","JPN":"今度の試合で確実に終わらせるべきだ。二度と歯向かうことのないように。","ENG":"We have to make sure that she won't mess with us again.","TWN":"這次比賽一定要處理乾淨，不准再有第二次。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"이건…… 뭐죠?","JPN":"これは……何ですか？","ENG":"What's... this?","TWN":"這是……什麼？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"거기 적힌 건물로 가면 도와 줄 사람이 있을 거야. 내 예전 지인이지.","JPN":"そこに書いているビルに行けば、力を貸してくれる人がいるはずだ。私の昔の知り合いでな。","ENG":"Go to that address, and you'll find someone who'll help you out. She's an old acquaintance of mine.","TWN":"你去那上面寫的大樓，那裡有能幫忙的人，是我的一個老朋友。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};